section.artwork:
AICatalog = {
  $schema: text,
  specVersion: text,
  ? host: HostInfo,
  entries: [* CatalogEntry],
  ? metadata: { * text => any }
}

HostInfo = {
  name: text,
  ? id: text,
  ? documentationUrl: text,
  ? logoUrl: text,
  ? trustCard: TrustCard
}

CatalogEntry = {
  id: text,
  name: text,
  mediaType: text,
  (url: text // inline: any),
  ? description: text,
  ? tags: [* text],
  ? publisher: Publisher,
  ? trustCard: TrustCard,
  ? updatedAt: tdate,
  ? metadata: { * text => any }
}

TrustCard = { identity: text, ? identityType: text, ? trustSchema: TrustSchema, ? attestations: [* Attestation], ? provenance: [* ProvenanceLink], ? privacyPolicyUrl: text, ? termsOfServiceUrl: text, ? signature: text, ? metadata: { * text => any } }
Publisher = { id: text, name: text, ? identityType: text }
TrustSchema = { id: text, version: text, ? governanceUri: text, ? verificationMethods: [* text] }
Attestation = { type: text, uri: text, mediaType: text, ? digest: text, ? size: uint, ? description: text }
ProvenanceLink = { relation: text, sourceId: text, ? sourceDigest: text, ? registryUri: text, ? statementUri: text, ? signatureRef: text }

